import { useState } from "react";
import { MdArrowBack } from "react-icons/md";
import { useNavigate, useLocation } from "react-router-dom";
import axios from "axios";
import "./verifyotp.css";

const VerifyOTP = () => {
  const [otp, setOtp] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();
  const email = location.state?.email; // Get email passed from Forgot Password page

  const handleOTPVerification = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setLoading(true);

    try {
      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", { email, otp });
      setSuccess(response.data.message);
      setTimeout(() => navigate("/reset-password", { state: { email } }), 2000); // Redirect to Reset Password
    } catch (error) {
      setError(error.response?.data?.message || "Invalid OTP. Try again!");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="verify-otp-container">
      <div className="back-to-forgot" onClick={() => navigate("/forgot-password")}> <MdArrowBack /> </div>
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />
      <h2 className="verify-otp-title">Verify OTP</h2>
      <p className="instruction-text">Enter the OTP sent to your email.</p>
      <form onSubmit={handleOTPVerification} className="verify-otp-form">
        <input
          type="text"
          placeholder="Enter OTP"
          value={otp}
          onChange={(e) => setOtp(e.target.value)}
          maxLength="6"
        />
        <button type="submit" className="verify-button" disabled={loading}>
          {loading ? "Verifying..." : "Verify OTP"}
        </button>
        <div className="message-container">
          {error && <p className="error-message">{error}</p>}
          {success && <p className="success-message">{success}</p>}
        </div>
      </form>
    </div>
  );
};

export default VerifyOTP;
